<?php namespace App\Repositories\Fee;use App\Repositories\BaseRepository;use App\Models\Fee\FeeDueTracking;use Illuminate\Database\Eloquent\Collection;class FeeDueTrackingRepository extends BaseRepository{    public function __construct(FeeDueTracking $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByInstallment(int $installmentId): Collection    {        return $this->findByField('fee_installment_id', $installmentId);    }    public function getOverdueRecords(): Collection    {        return $this->query()->where('due_date', '<', now())->where('status', 'unpaid')->get();    }    public function getByDueDate(string $date): Collection    {        return $this->query()->whereDate('due_date', $date)->get();    }    public function getByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getStudentsWithPendingDues(): Collection    {        return $this->query()->whereIn('status', ['unpaid', 'partial'])->with('student')->get();    }    public function getDueRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('due_date', [$startDate, $endDate])->get();    }    public function getTotalOverdueAmount(): float    {        return $this->query()->where('due_date', '<', now())->where('status', 'unpaid')->sum('amount');    }    public function markAsNotified(int $id): bool    {        return $this->update($id, ['notified_at' => now(), 'notification_sent' => true]);    }}